#!/usr/bin/env bash
# ATLAS Shell Aliases Generator
# Usage: ./shell-aliases.sh [WORKSPACE_PATH]
# Generates shell functions for launching Claude Code sessions.
# Detects Ptyxis terminal and uses exec -a bash hack for clean tab titles.

set -euo pipefail

WORKSPACE="${1:-$HOME/workspace_atlas}"

# Detect if Ptyxis terminal needs exec -a bash hack
use_exec_hack=false
if [ -n "${PTYXIS_VERSION:-}" ] || pgrep -x ptyxis >/dev/null 2>&1; then
  use_exec_hack=true
fi

cat <<HEADER
# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
# 🏛️ ATLAS — Claude Code Session Launchers
# Generated by: /atlas setup ($(date +%Y-%m-%d))
# Workspace: ${WORKSPACE}
# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

HEADER

if [ "$use_exec_hack" = true ]; then
  # Ptyxis: exec -a bash hides full command from tab title
  cat <<EOF
# Ptyxis terminal detected — using exec -a bash for clean tab titles
atlas() {
  local topic="\${1:-}"; local name="atlas\${topic:+-\$topic}"
  cd ${WORKSPACE}/atlas && (exec -a bash claude --chrome -n "\$name" "\${@:2}")
}
atlas-w() {
  local topic="\${1:-}"; local name="atlas\${topic:+-\$topic}"
  cd ${WORKSPACE}/atlas && (exec -a bash claude --chrome -w -n "\$name" "\${@:2}")
}
atlas-synapse() {
  local topic="\${1:-}"; local name="synapse\${topic:+-\$topic}"
  cd ${WORKSPACE}/projects/atlas/synapse && (exec -a bash claude --chrome -n "\$name" "\${@:2}")
}
atlas-synapse-w() {
  local topic="\${1:-}"; local name="synapse\${topic:+-\$topic}"
  cd ${WORKSPACE}/projects/atlas/synapse && (exec -a bash claude --chrome -w -n "\$name" "\${@:2}")
}
EOF
else
  cat <<EOF
atlas() {
  local topic="\${1:-}"; local name="atlas\${topic:+-\$topic}"
  cd ${WORKSPACE}/atlas && claude --chrome -n "\$name" "\${@:2}"
}
atlas-w() {
  local topic="\${1:-}"; local name="atlas\${topic:+-\$topic}"
  cd ${WORKSPACE}/atlas && claude --chrome -w -n "\$name" "\${@:2}"
}
atlas-synapse() {
  local topic="\${1:-}"; local name="synapse\${topic:+-\$topic}"
  cd ${WORKSPACE}/projects/atlas/synapse && claude --chrome -n "\$name" "\${@:2}"
}
atlas-synapse-w() {
  local topic="\${1:-}"; local name="synapse\${topic:+-\$topic}"
  cd ${WORKSPACE}/projects/atlas/synapse && claude --chrome -w -n "\$name" "\${@:2}"
}
EOF
fi

cat <<'EOF'

# Quick navigation
alias wa='cd ${ATLAS_ROOT:-$HOME/workspace_atlas}'
EOF
